import { createCuratedRoleProfile } from "../profileFactory.js";

const PARENT = "寢宮寵妃系列";

function c(id, title, series, tags, palette, costumeCore, jewelry, prop, place, pose, background, lighting, atmosphere, cupSize = "正常比例") {
  return createCuratedRoleProfile({
    id,
    title,
    parentCategory: PARENT,
    series: `${PARENT}／${series}`,
    themeHint: `${title} ${series} ${tags.join(" ")}`,
    aliases: [PARENT, series, title, ...tags],
    identity: title.replace("・", ""),
    palette,
    costumeCore,
    jewelry,
    prop,
    place,
    foreground: `${prop}、近景絲緞裙擺反光、床榻錦墊與珠寶細節`,
    midground: `真人成年女性${pose}`,
    background,
    action: `${pose}；手部優先扶床榻、整理披袍、輕觸軟枕、牽起外袍或自然垂落，${prop}可作近景或床邊道具，不必手持；臉部完整清楚，手不遮臉，姿態成熟端正`,
    lighting,
    atmosphere,
    cupSize,
  });
}

